def magic_square_test(matrix):
    n = len(matrix)
    for row in matrix:
        if len(row) != n:
            return False
    elements = set()
    for row in matrix:
        for num in row:
            if num in elements:
                return False
            elements.add(num)
    expected_sum = n * (n * n + 1) // 2
    for row in matrix:
        if sum(row) != expected_sum:
            return False
    for col in range(n):
        total = 0
        for row in matrix:
            total += matrix[row][col]
        if total != expected_sum:
            return False
    diag1 = 0
    diag2 = 0
    for i in range(n):
        diag1 += matrix[i][i]
        diag2 += matrix[i][n-1-i]
    if diag1 != diag2:
        return False
    return True
